+                    common_mistakes: vec!["Forgetting to specify folder_id defaults to Inbox".into()],
+                    examples: vec!["{}".into(), "{\"folder_id\":\"Drafts\",\"top\":10}".into()],
+                    related: vec![CapabilityId::from_static(OP_GET_MESSAGE)],
