+                    "type": "object",
+                    "required": ["subject", "start", "end"],
+                    "properties": {
+                        "subject": { "type": "string" },
+                        "start": { "type": "string" },
+                        "end": { "type": "string" },
+                        "body": { "type": "string" },
+                        "location": { "type": "string" }
